import Navbar from "./Navbar";
import Title from './Title'
import theme from '../theme'

const Layout = ({ children }) => (
  <>
    <style>{style}</style>
    <div className='wrapper'>
      <Title />
      <Navbar />
      {children}
    </div>
  </>
);

const style = `
  * {
    font-family:Roboto;
  }
  ol {
      padding-left:1rem;
  }
  .wrapper {
    width:70vw;
    margin:auto;
    min-width:600px;
  }
  body {
    background-color:${theme.darkBackground};
  }

  a {
    color:grey;
    text-decoration:none;
  }
  a:hover {
    color:white;
  }
  li {
    color:white;
  }
`;

export default Layout;
